import React from "react";
import { Bar } from "react-chartjs-2";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
);

function Analytics() {
  const data = {
    labels: ["CSE", "IT", "EXTC", "Mechanical"],
    datasets: [
      {
        label: "Placed Students",
        data: [40, 25, 18, 10],
        backgroundColor: "#2563eb",
      },
    ],
  };

  const options = {
    responsive: true,
    plugins: {
      legend: {
        labels: {
          color: "white",
        },
      },
    },
    scales: {
      x: {
        ticks: {
          color: "white",
        },
      },
      y: {
        ticks: {
          color: "white",
        },
      },
    },
  };

  return (
    <>
      <h1 style={{ marginBottom: "30px", color: "white" }}>
        Placement Analytics
      </h1>

      <div style={{ width: "700px" }}>
        <Bar data={data} options={options} />
      </div>
    </>
  );
}

export default Analytics;
